-- ----------------------------
-- Table structure for admin_permissions
-- ----------------------------
DROP TABLE IF EXISTS `admin_permissions`;
CREATE TABLE `admin_permissions` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '权限ID（主键）',
  `permission_code_or_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '权限代码（唯一标识，如：course.create, news.publish）',
  `icon` varchar(300) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '图标',
  `permission_name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL COMMENT '权限名称（如：创建课程，发布资讯）',
  `description` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '权限描述',
  `parent_id` bigint NOT NULL COMMENT '父级ID(上一级权限ID)',
  `root_id` bigint DEFAULT NULL COMMENT '根节点ID(顶级权限ID)',
  `belongs_platform` tinyint NOT NULL COMMENT '归属平台(1=PC、2=小程序)',
  `permission_type` tinyint NOT NULL DEFAULT '1' COMMENT '权限类型(1=菜单、2=权限点)',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '排序权重',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `permission_code` (`permission_code_or_path`),
  KEY `idx_parent` (`parent_id`),
  KEY `idx_root` (`root_id`),
  KEY `idx_platform` (`belongs_platform`),
  KEY `idx_type` (`permission_type`)
) ENGINE=InnoDB AUTO_INCREMENT=165 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='权限表';

